//
//  SettingsCommand.Model.swift
//  Radiacode
//
//  Created by Matvey Kozin on 26.09.2023.
//

import Foundation

enum SettingsModel: Equatable {

    case device(DeviceControl)
    case sound(SoundControl)
    case vibro(VibrationControl)

    var command: UInt32 {
        switch self {
        case .device:
            BluetoothCommandOperation.deviceControl.rawValue
        case .sound:
            BluetoothCommandOperation.soundControl.rawValue
        case .vibro:
            BluetoothCommandOperation.vibroControl.rawValue
        }
    }

    /// Структура флагов и битовых полей для управления устройством
    enum DeviceControl: UInt8, Equatable {
        /// Команда/признак включения/выключения прибора
        case power
        /// Команда/признак включения/выключения дисплея
        case display
        /// Опция - разрешает/запрещает звуковые сигналы
        case sound
        /// Опция - разрешает/запрещает световые сигналы
        case leds
        /// Опция - разрешает/запрещает вибро-сигналы
        case vibration
        /// Команда/признак включения/выключения заряда аккумулятора
        case charger
        /// Команда/признак запуска/останова пользовательского измерения
        case userRun

        /// shifted value
        var value: UInt32 {
            0x01 << rawValue
        }
    }

    /// Структура флагов и битовых полей для управления звуковыми сигналами
    enum SoundControl: UInt8, Equatable, CaseIterable {
        /// Опция - разрешение/запрет сигнала по нажатию на кнопку
        case button
        /// Опция - разрешение/запрет сигнала по регистрации частиц
        case clickers
        /// Опция - разрешение/запрет сигнала по превышению первого порога по мощности дозы
        case alarmDoseRateL1
        /// Опция - разрешение/запрет сигнала по превышению второго порога по мощности дозы
        case alarmDoseRateL2
        /// Опция - разрешение/запрет сигнала по зашкаливанию мощности дозы
        case alarmDoseRate
        /// Опция - разрешение/запрет сигнала по превышению первого порога по дозе
        case alarmCollectedDoseL1
        /// Опция - разрешение/запрет сигнала по превышению второго порога по дозе
        case alarmCollectedDoseL2
        /// Опция - разрешение/запрет сигнала по зашкаливанию дозы
        case alarmCollectedDose
        /// Опция - разрешение/запрет сигналов по установке/разрыву связи с host-ом
        case connections
        /// Опция - разрешение/запрет сигналов по включению/выключению прибора
        case power
        /// Опция - разрешение/запрет сигнала по превышению первого порога по скорости счета
        case alarmCountRateL1
        /// Опция - разрешение/запрет сигнала по превышению первого порога по скорости счета
        case alarmCountRateL2
        /// Опция - разрешение/запрет сигнала по зашкаливанию скорости счета
        case alarmCountRate

        /// Агрегат всех alarm-битов. Не отдельный бит — псевдо-case. Sentinel rawValue.
        case alarm = 255

        var value: UInt32 {
            switch self {
            case .alarm: Self.alarmMask
            default: 0x01 << rawValue
            }
        }

        private var isAlarm: Bool {
            switch self {
            case .alarmDoseRateL1, .alarmDoseRateL2, .alarmDoseRate,
                 .alarmCollectedDoseL1, .alarmCollectedDoseL2, .alarmCollectedDose,
                 .alarmCountRateL1, .alarmCountRateL2, .alarmCountRate:
                true
            default:
                false
            }
        }

        /// Маска всех alarm-битов в VSFR_SOUND_CTRL.
        static let alarmMask: UInt32 = allCases.filter(\.isAlarm).reduce(0) { $0 | $1.value }
    }

    /// Структура флагов и битовых полей для управления вибро-сигналами
    enum VibrationControl: UInt8, Equatable, CaseIterable {
        /// Опция - разрешение/запрет сигнала по нажатию на кнопку
        case button
        /// Опция - разрешение/запрет сигнала по регистрации частиц
        case clickers
        /// Опция - разрешение/запрет сигнала по превышению первого порога по мощности дозы
        case alarmDoseRateL1
        /// Опция - разрешение/запрет сигнала по превышению второго порога по мощности дозы
        case alarmDoseRateL2
        /// Опция - разрешение/запрет сигнала по зашкаливанию мощности дозы
        case alarmDoseRate
        /// Опция - разрешение/запрет сигнала по превышению первого порога по дозе
        case alarmCollectedDoseL1
        /// Опция - разрешение/запрет сигнала по превышению второго порога по дозе
        case alarmCollectedDoseL2
        /// Опция - разрешение/запрет сигнала по зашкаливанию дозы
        case alarmCollectedDose
        /// Опция - разрешение/запрет сигнала по превышению первого порога по скорости счета
        case alarmCountRateL1 = 10
        /// Опция - разрешение/запрет сигнала по превышению первого порога по скорости счета
        case alarmCountRateL2
        /// Опция - разрешение/запрет сигнала по зашкаливанию скорости счета
        case alarmCountRate

        /// Агрегат всех alarm-битов. Не отдельный бит — псевдо-case. Sentinel rawValue.
        case alarm = 255

        var value: UInt32 {
            switch self {
            case .alarm: Self.alarmMask
            default: 0x01 << rawValue
            }
        }

        private var isAlarm: Bool {
            switch self {
            case .alarmDoseRateL1, .alarmDoseRateL2, .alarmDoseRate,
                 .alarmCollectedDoseL1, .alarmCollectedDoseL2, .alarmCollectedDose,
                 .alarmCountRateL1, .alarmCountRateL2, .alarmCountRate:
                true
            default:
                false
            }
        }

        /// Маска всех alarm-битов в VSFR_VIBRO_CTRL.
        static let alarmMask: UInt32 = allCases.filter(\.isAlarm).reduce(0) { $0 | $1.value }
    }
}

