import Foundation

enum BluetoothCommandOperation: UInt32 {

    // MARK: - System

    /// SET_EXCHANGE
    case setExchange = 0x80000007

    /// VS_CONFIGURATION
    case configuration = 0x00000002

    /// SET_LOCAL_TIME
    case setLocalTime = 0x80000A04

    /// VSFR_DEVICE_TIME
    case deviceTime = 0x00000504

    // MARK: - Settings

    /// VSFR_DEVICE_CTRL
    case deviceControl = 0x00000500

    /// VSFR_SOUND_CTRL
    case soundControl = 0x00000520

    /// VSFR_VIBRO_CTRL
    case vibroControl = 0x00000530

    // MARK: - Actions

    /// VSFR_PLAY_SIGNAL
    case playSignal = 0x000005E1

    // MARK: - Data

    /// VS_DATA_BUF
    case dataBuffer = 0x00000100

    /// RC_VSFR_DOSE_RESET
    case doseReset = 0x00008007

    // MARK: - Spectrum

    /// RC_VS_SPEC_RESET
    case spectrumReset = 0x00000207

    /// RC_VS_SPEC_DIFF
    case spectrumDiff = 0x00000206

    /// RC_VS_SPEC_ACCUM
    case spectrumAccum = 0x00000205

    /// RC_VS_SPECTRUM
    case spectrum = 0x00000200

    /// RC_VS_ENERGY_CALIB
    case energyCalibration = 0x00000202

    // MARK: - Firmware

    /// RD_SIGNAT
    case readFlashSignature = 0x80000101

    /// GET_VERSION
    case getFirmwareVersion = 0x8000000A

    /// FW_IMAGE_GET_INFO
    case getFirmwareImageInfo = 0x80000012

    /// FW_IMAGE_UPDATE
    case firmwareImageUpdate = 0x80000014

    /// FW_IMAGE_WRITE
    case firmwareImageWrite = 0x80000013

    // MARK: - DoseRate

    /// RC_VSFR_DR_LEV1_uR_h
    case doseRateAlarmLevel1 = 0x00008000

    /// RC_VSFR_DR_LEV2_uR_h
    case doseRateAlarmLevel2 = 0x00008001

    // MARK: - Dose

    /// RC_VSFR_DS_LEV1_100uR
    case doseAlarmLevel1 = 0x00008002

    /// RC_VSFR_DS_LEV2_100uR
    case doseAlarmLevel2 = 0x00008003

    // MARK: - CountRate

    /// RC_VSFR_CR_LEV1_cp10s
    case countRateAlarmLevel1 = 0x00008008

    /// RC_VSFR_CR_LEV2_cp10s
    case countRateAlarmLevel2 = 0x00008009

    /// RC_VSFR_TEMP_UNITS
    case temperatureUnit = 0x00008016
}

//
//  Alarm.swift
//  RadiaCode
//
//  Created by Matvey Kozin on 04.09.2025.
//

import Foundation

/// Пороговые значения тревог
@Observable
final class Alarm: Equatable, Codable {

    enum Consts {
        static let initialMaxCountRate: Float = 30.0
        static let initialMaxDoseRate: Float = 0.7
    }

    /// Уровни тревог
    struct Level: Equatable, Codable {

        let radiationType: RadiationType
        /// Первый порог
        var level1: Decimal?
        /// Второй порог
        var level2: Decimal?
        /// Зашкал
        var offScale: Decimal?

        /// Проверка значения на Алерт
        /// - Parameter value: значение
        /// - Returns: алерт
        func checkValue(_ value: Float) -> SignalizationAlarmLevel {
            if let offScale = offScale?.floatValue, value >= offScale {
                return .offScale
            }
            if let level2 = level2?.floatValue, value >= level2 {
                return .level2
            }
            if let level1 = level1?.floatValue, value >= level1 {
                return .level1
            }
            return .normal
        }

        var isEmpty: Bool {
            level1 == nil && level2 == nil
        }
    }

    /// Пороги по скорости счета [имп. за 10 с]
    var countRate: Level
    /// Пороги по мощности дозы
    var doseRate: Level
    /// Пороги по дозе
    var dose: Level

    var isEmpty: Bool {
        countRate.isEmpty && doseRate.isEmpty && dose.isEmpty
    }

    init(
        countRate: Level = Level(radiationType: .radiationLevel(.countRate)),
        doseRate: Level = Level(radiationType: .radiationLevel(.doseRate)),
        dose: Level = Level(radiationType: .dose)
    ) {
        self.countRate = countRate
        self.doseRate = doseRate
        self.dose = dose
    }

    enum CodingKeys: String, CodingKey {
        case countRate
        case doseRate
        case dose
    }

    required init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        self.countRate = try container.decode(Level.self, forKey: .countRate)
        self.doseRate = try container.decode(Level.self, forKey: .doseRate)
        self.dose = try container.decode(Level.self, forKey: .dose)
    }

    func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        try container.encode(countRate, forKey: .countRate)
        try container.encode(doseRate, forKey: .doseRate)
        try container.encode(dose, forKey: .dose)
    }

    static func == (lhs: Alarm, rhs: Alarm) -> Bool {
        lhs.countRate == rhs.countRate &&
        lhs.doseRate == rhs.doseRate &&
        lhs.dose == rhs.dose
    }
}

