//
//  AlarmsLevelViewModel.swift
//  Radiacode
//
//  Created by Matvey Kozin on 19.06.2024.
//

import Foundation
import FactoryKit

final class AlarmsLevelViewModel: ObservableObject {

    @Injected(\.deviceManager) private var deviceManager
    @Injected(\.dataBufferSetupRepository) private var dataBufferSetupRepository

    func updateAlarms(radiationType: RadiationType, level1: Decimal?, level2: Decimal?) async {
        if let level1 {
            await updateSettings(setting: radiationType.deviceSettingsLevel1, value: radiationType.deviceValue(value: level1))
        }
        if let level2 {
            await updateSettings(setting: radiationType.deviceSettingsLevel2, value: radiationType.deviceValue(value: level2))
        }
    }

    private func updateSettings(setting: BluetoothCommandOperation, value: UInt32) async {
        await deviceManager.send(command: SettingsCommand(
            setting: setting, action: .write, payload: value
        ))
    }
}

private extension RadiationType {

    var deviceSettingsLevel1: BluetoothCommandOperation {
        switch self {
        case .radiationLevel(let level):
            switch level {
            case .countRate:
                .countRateAlarmLevel1
            case .doseRate:
                .doseRateAlarmLevel1
            }
        case .dose:
            .doseAlarmLevel1
        }
    }

    var deviceSettingsLevel2: BluetoothCommandOperation {
        switch self {
        case .radiationLevel(let level):
            switch level {
            case .countRate:
                .countRateAlarmLevel2
            case .doseRate:
                .doseRateAlarmLevel2
            }
        case .dose:
            .doseAlarmLevel2
        }
    }

    func deviceValue(value: Decimal) -> UInt32 {
        switch self {
        case .radiationLevel(let level):
            switch level {
            case .countRate:
                UInt32(value.floatValue * 10)
            case .doseRate:
                UInt32(value.floatValue * 100)
            }
        case .dose:
            UInt32(value.floatValue)
        }
    }
}

