//
//  Created by Matvey Kozin on 15.11.2023.
//

import Foundation

typealias EventId = DataBufferCommand.Response.Frame.EventId

extension DataBufferCommand.Response.Frame {

    enum EventId: UInt8, CaseIterable, Codable {
        /// Обесточивание прибора
        case powerOff
        /// Включение питания прибора
        case powerOn
        ///  Аварийное выключение прибора по разряду элементов питания
        case lowBatteryPowerOff
        /// Изменились параметры (один или несколько) конфигурации прибора
        case config
        /// Обнуление дозы
        case doseReset
        /// Пользовательская метка
        case userEvent
        /// Сигнал разряда элементов питания перед аварийным выключением прибора
        case lowBattery
        /// Начало заряда аккумулятора
        case chargeOn
        /// Окончание заряда аккумулятора
        case chargeOff
        /// Тревога 1 по мощности дозы
        case doseRateAlarmLvl1
        /// Тревога 2 по мощности дозы
        case doseRateAlarmLvl2
        /// Зашкал по мощности дозы
        case doseRateOffScale
        /// Тревога 1 по дозе
        case doseAlarmLvl1
        /// Тревога 2 по дозе
        case doseAlarmLvl2
        /// Зашкал по дозе
        case doseOffScale
        /// Слишком низкая  температура (ниже диапазона допустимых значений)
        case temperatureLow
        /// Слишком высокая температура (выше диапазона допустимых значений)
        case temperatureHigh
        /// Имеется текстовое сообщение (нужно прочитать строку VS_TEXT_MESSAGE)
        case textMessage
        /// Имеется снимок участков памяти (нужно прочитать строку VS_MEM_SNAPSHOT)
        case memorySnapshot
        /// Выполнен сброс (перезапуск накопления) спектра
        case spectrumReset
        /// Тревога 1 по скорости счета
        case countRateLvl1
        /// Тревога 2 по скорости счета
        case countRateLvl2
        /// Зашкал по скорости счета
        case countRateOffScale

        var name: String {
            switch self {
            case .powerOff: "RC_EV_PwrOff"
            case .powerOn: "RC_EV_PwrOn"
            case .lowBatteryPowerOff: "RC_EV_LowVBat_PwOff"
            case .config: "RC_EV_SetConfig"
            case .doseReset: "RC_EV_DoseReset"
            case .userEvent: "RC_EV_UserEvent"
            case .lowBattery: "RC_EV_LowVBat"
            case .chargeOn: "RC_EV_ChargeOn"
            case .chargeOff: "RC_EV_ChargeOff"
            case .doseRateAlarmLvl1: "RC_EV_DRA_Lev1"
            case .doseRateAlarmLvl2: "RC_EV_DRA_Lev2"
            case .doseRateOffScale: "RC_EV_DRA_OutSc"
            case .doseAlarmLvl1: "RC_EV_DSA_Lev1"
            case .doseAlarmLvl2: "RC_EV_DSA_Lev2"
            case .doseOffScale: "RC_EV_DSA_OutSc"
            case .temperatureLow: "RC_EV_TA_TooLow"
            case .temperatureHigh: "RC_EV_TA_TooHigh"
            case .textMessage: "RC_EV_TextMessage"
            case .memorySnapshot: "RC_EV_MemSnapshot"
            case .spectrumReset: "RC_EV_SpecReset"
            case .countRateLvl1: "RC_EV_CRA_Lev1"
            case .countRateLvl2: "RC_EV_CRA_Lev2"
            case .countRateOffScale: "RC_EV_CRA_OutSc"
            }
        }

        var isAlarm: Bool {
            isCountRateAlarm || isDoseRateAlarm
        }

        var isDoseAlarm: Bool {
            switch self {
            case .doseAlarmLvl1,
                    .doseAlarmLvl2,
                    .doseOffScale:
                true
            default:
                false
            }
        }

        var isCountRateAlarm: Bool {
            switch self {
            case .countRateLvl1,
                    .countRateLvl2,
                    .countRateOffScale:
                true
            default:
                false
            }
        }

        var isDoseRateAlarm: Bool {
            switch self {
            case .doseRateAlarmLvl1,
                    .doseRateAlarmLvl2,
                    .doseRateOffScale:
                true
            default:
                false
            }
        }

        var isTemperature: Bool {
            switch self {
            case .temperatureLow, .temperatureHigh:
                true
            default:
                false
            }
        }

        var signalizationAlarm: SignalizationAlarmLevel {
            switch self {
            case .countRateLvl1, .doseRateAlarmLvl1, .doseAlarmLvl1:
                .level1
            case .countRateLvl2, .doseRateAlarmLvl2, .doseAlarmLvl2:
                .level2
            case .countRateOffScale, .doseRateOffScale, .doseOffScale:
                .offScale
            default:
                .normal
            }
        }
    }
}

//
//  PlaySignalCommand.swift
//  Radiacode
//
//  Created by Matvey Kozin on 30.11.2023.
//

import Foundation

/// Воспроизведение на приборе указанного сигнала или прекращение воспроизведения текущего сигнала.
struct PlaySignalCommand: BluetoothCommand {

    enum Action: UInt32 {
        case stop
        case play
    }

    let request: BluetoothCommandRequest

    init(action: Action) {
        self.request = .init(
            type: .writeVirtualSFR,
            command: .playSignal,
            payload: action.rawValue.asBytes
        )
    }
}

