8	import Foundation
9	
10	@Observable
11	final class AlarmLevelSetupViewModel {
12	    
13	    private final class LastState {
14	        var last1: Decimal
15	        var last2: Decimal
16	        
17	        init(last1: Decimal, last2: Decimal) {
18	            self.last1 = last1
19	            self.last2 = last2
20	        }
21	    }
22	    
23	    private let alarmLevel: Alarm.Level
24	    
25	    var displayedValueLevel1: AlarmWheelModel
26	    var displayedValueLevel2: AlarmWheelModel
27	            
28	    init(alarmLevel: Alarm.Level) {
29	        self.alarmLevel = alarmLevel
30	        let radiationType = alarmLevel.radiationType
31	       
32	        func makeValues(minStep: Decimal, switchAt: Decimal) -> [Decimal] {
33	            let maxValue = alarmLevel.offScale ?? radiationType.defaultMaxValue
34	            
35	            func step(for value: Decimal) -> Decimal {
36	                var step = minStep
37	                var threshold = switchAt
38	
39	                while value >= threshold * 10 {
40	                    step *= 10
41	                    threshold *= 10
42	                }
43	
44	                return step
45	            }
46	
47	            var values: [Decimal] = []
48	            var value = maxValue
49	
50	            while value >= 0 {
51	                values.append(value)
52	                if value == 0 { break }
53	
54	                value -= step(for: value)
55	                if value < 0 {
56	                    value = 0
57	                }
58	            }
59	
60	            return values
61	        }
62	        
63	        let values: [Decimal] = {
64	            switch radiationType {
65	            case .radiationLevel(let level):
66	                switch level {
67	                case .countRate:
68	                    makeValues(minStep: 0.1, switchAt: 20)
69	
70	                case .doseRate:
71	                    makeValues(minStep: 0.01, switchAt: 2)
72	                }
73	
74	            case .dose:
75	                makeValues(minStep: 1, switchAt: 100)
76	            }
77	        }()
78	        
79	        self.displayedValueLevel1 = .init(initialValue: alarmLevel.level1 ?? 0, radiationType: radiationType, values: values)
