//
//  AlarmLevelSetupViewModel.swift
//  RadiaCode
//
//  Created by Matvey Kozin on 18.11.2025.
//

import Foundation

@Observable
final class AlarmLevelSetupViewModel {

    private final class LastState {
        var last1: Decimal
        var last2: Decimal

        init(last1: Decimal, last2: Decimal) {
            self.last1 = last1
            self.last2 = last2
        }
    }

    private let alarmLevel: Alarm.Level

    var displayedValueLevel1: AlarmWheelModel
    var displayedValueLevel2: AlarmWheelModel

    init(alarmLevel: Alarm.Level) {
        self.alarmLevel = alarmLevel
        let radiationType = alarmLevel.radiationType

        func makeValues(minStep: Decimal, switchAt: Decimal) -> [Decimal] {
            let maxValue = alarmLevel.offScale ?? radiationType.defaultMaxValue

            func step(for value: Decimal) -> Decimal {
                var step = minStep
                var threshold = switchAt

                while value >= threshold * 10 {
                    step *= 10
                    threshold *= 10
                }

                return step
            }

            var values: [Decimal] = []
            var value = maxValue

            while value >= 0 {
                values.append(value)
                if value == 0 { break }

                value -= step(for: value)
                if value < 0 {
                    value = 0
                }
            }

            return values
        }

        let values: [Decimal] = {
            switch radiationType {
            case .radiationLevel(let level):
                switch level {
                case .countRate:
                    makeValues(minStep: 0.1, switchAt: 20)

                case .doseRate:
                    makeValues(minStep: 0.01, switchAt: 2)
                }

            case .dose:
                makeValues(minStep: 1, switchAt: 100)
            }
        }()

        self.displayedValueLevel1 = .init(initialValue: alarmLevel.level1 ?? 0, radiationType: radiationType, values: values)
        self.displayedValueLevel2 = .init(initialValue: alarmLevel.level2 ?? 0, radiationType: radiationType, values: values)

        let state = LastState(last1: displayedValueLevel1.selectedValue, last2: displayedValueLevel2.selectedValue)

        withObservationTracking { [weak self] in
            guard let self else { return }
            let level1 = self.displayedValueLevel1.selectedValue
            let level2 = self.displayedValueLevel2.selectedValue

            let level1Changed = (level1 != state.last1)
            let level2Changed = (level2 != state.last2)

            defer {
                state.last1 = level1
                state.last2 = level2
            }

            if level2Changed && !level1Changed {
                // двигают level2 -> level1 следует за ним
                if level2 < level1 {
                    self.displayedValueLevel1.selectedValue = level2
                }
            } else if level1Changed && !level2Changed {
                // двигают level1 -> level2 следует за ним
                if level1 > level2 {
                    self.displayedValueLevel2.selectedValue = level1
                }
            }
        }
    }

    func alarmsChanged() -> Bool {
        alarmLevel.level1 != displayedValueLevel1.selectedValue || alarmLevel.level2 != displayedValueLevel2.selectedValue
    }
}

