private func configure(connectedDevice: BluetoothDevice, didRetry: Bool = false) async throws {
    let configResult = await connectedDevice.send(command: ConfigurationCommand())
    do {
        let response = try configResult.get()
        let configurationSettings = try configurationParser.parse(configuration: response)
        connectedDevice.configurationSettings = configurationSettings

        let specFormatVersion = configurationSettings.specFormatVersion
        let disableSpectrum = configurationSettings.disableSpectrum

        await spectrumDataRepository?.setupSpectrumSetting(specFormatVersion: specFormatVersion, spectrumDisabled: disableSpectrum)
        await spectrogramDataRepository?.setupSpectrumSetting(specFormatVersion: specFormatVersion, spectrumDisabled: disableSpectrum)
        await activityDataRepository?.setupSpectrumSetting(specFormatVersion: specFormatVersion, spectrumDisabled: disableSpectrum)

        connectedDevice.alarms.countRate.offScale = configurationSettings.maxCountRate
        connectedDevice.alarms.doseRate.offScale = configurationSettings.maxDoseRate
        connectedDevice.alarms.dose.offScale = configurationSettings.maxDose
    } catch {
        if !didRetry {
            try await configure(connectedDevice: connectedDevice, didRetry: true)
        } else {
            throw error
        }
    }
}

func updateDeviceSettings() async {
    guard let connectedDevice else { return }
    await getDeviceSettings(connectedDevice: connectedDevice)
}

func setupCalibrationSettings(_ action: EnergyCalibrationCommand.Action.Write) async {
    guard let connectedDevice else { return }
    await connectedDevice.send(command: EnergyCalibrationCommand(action: .write(action)))
    await fetchEnergyCalibration(for: connectedDevice)
}

