        await self.settingComposer.set(raw: response.register, value: response.value)
    }

    let vibroResult = await connectedDevice.send(command: SettingsCommand(setting: .vibroControl))
    if case .success(let response) = vibroResult {
        await self.settingComposer.set(raw: response.register, value: response.value)
    }

    let temperatureUnit = await connectedDevice.send(command: SettingsCommand(setting: .temperatureUnit))
    if case .success(let response) = temperatureUnit {
        connectedDevice.settings.temperatureUnit = TemperatureUnit(rawValue: response.value) ?? .celsius
    }

    let doseRateAlarmLevel1Result = await connectedDevice.send(command: SettingsCommand(setting: .doseRateAlarmLevel1))
    if case .success(let response) = doseRateAlarmLevel1Result {
        connectedDevice.alarms.doseRate.level1 = Decimal(response.value) / 100
    }
    let doseRateAlarmLevel2Result = await connectedDevice.send(command: SettingsCommand(setting: .doseRateAlarmLevel2))
    if case .success(let response) = doseRateAlarmLevel2Result {
        connectedDevice.alarms.doseRate.level2 = Decimal(response.value) / 100
    }

    let countRateAlarmLevel1Result = await connectedDevice.send(command: SettingsCommand(setting: .countRateAlarmLevel1))
    if case .success(let response) = countRateAlarmLevel1Result {
        connectedDevice.alarms.countRate.level1 = Decimal(response.value) / 10
    }

    let countRateAlarmLevel2Result = await connectedDevice.send(command: SettingsCommand(setting: .countRateAlarmLevel2))
    if case .success(let response) = countRateAlarmLevel2Result {
        connectedDevice.alarms.countRate.level2 = Decimal(response.value) / 10
    }

    let doseAlarmLevel1Result = await connectedDevice.send(command: SettingsCommand(setting: .doseAlarmLevel1))
    if case .success(let response) = doseAlarmLevel1Result {
        connectedDevice.alarms.dose.level1 = Decimal(response.value)
    }

    let doseAlarmLevel2Result = await connectedDevice.send(command: SettingsCommand(setting: .doseAlarmLevel2))
    if case .success(let response) = doseAlarmLevel2Result {
        connectedDevice.alarms.dose.level2 = Decimal(response.value)
    }        
}

