//
//  RadiationType.swift
//  Radiacode
//
//  Created by Matvey Kozin on 19.06.2024.
//

import Foundation
import SwiftUI

/// Тип радиации
enum RadiationType: Equatable, Codable, Hashable, Identifiable {

    var id: Self {
        self
    }

    enum Level: String, Equatable, Codable {
        case countRate
        case doseRate

        var accentColor: Color {
            switch self {
            case .countRate:
                .accentGreen
            case .doseRate:
                .accentBlue
            }
        }

        var title: LocalizedStringResource {
            switch self {
            case .countRate:
                .Localization.countRate
            case .doseRate:
                .Localization.doseRate
            }
        }

        var unit: LocalizedStringResource {
            switch self {
            case .countRate:
                .Localization.cps
            case .doseRate:
                .Localization.μSvH
            }
        }
    }

    /// Уровни радиации
    case radiationLevel(Level)
    /// Доза
    case dose

    var title: LocalizedStringResource {
        switch self {
        case .radiationLevel(let level):
            level.title
        case .dose:
            .Localization.dose
        }
    }

    var unit: LocalizedStringResource {
        switch self {
        case .radiationLevel(let level):
            level.unit
        case .dose:
            .Localization.μSv
        }
    }

    var defaultMaxValue: Decimal {
        switch self {
        case .radiationLevel(let level):
            switch level {
            case .countRate:
                50000
            case .doseRate:
                1000
            }
        case .dose:
            10000000
        }
    }

    func unitByValue(value: Decimal) -> LocalizedStringResource {
        if self == .dose {
            if value >= 1_000_000 {
                return .Localization.sv
            } else if value >= 1000 {
                return .Localization.mSv
            }
        }
        return self.unit
    }

    func scale(value: Decimal) -> Decimal {
        if self == .dose {
            if value >= 1_000_000 {
                return value / 1_000_000
            } else if value >= 1000 {
                return value / 1000
            }
        }
        return value
    }
}

// MARK: - Сustom Decodable
extension RadiationType {

    private enum RadiationKey: String, CodingKey {
        case radiationLevel
        case dose
    }

    init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: RadiationKey.self)

        if container.contains(.dose) {
            self = .dose
            return
        }

        if container.contains(.radiationLevel) {
            if let level = try? container.decode([String: String].self, forKey: .radiationLevel) {
                for value in level.values {
                    if let level = RadiationType.Level(rawValue: value) {
                        self = .radiationLevel(level)
                        return
                    }
                }
            }
        }

        // Это жуткий костыль, чтобы убрать падения, при извлечении данных в SwiftData throw приводит к падению
        self = .radiationLevel(.countRate)
    }
}

