    func startRealTimeData()
    /// Останавливает загрузку данных с прибора
    func cancelRealTimeData()
}

protocol DeviceSetupManager {
    /// Подключено новое устройство
    var connectedDeviceSubject: PassthroughSubject<DeviceManagerImpl.ConnectedDeviceState, Never> { get }
    /// Подключение устройства
    /// - Parameter device: устройство
    func setup(device: BluetoothDevice)
    /// Установка первоначального соединения для выполнения команд
    func setupInitialConnectionObserver()
    /// Устанавливает настройки калибровочных коэффицентов
    /// - Parameter action: коэффициенты
    func setupCalibrationSettings(_ action: EnergyCalibrationCommand.Action.Write) async
    /// Сброс устройства
    func reset() async
    /// Обновляет настройки устройства
    func updateDeviceSettings() async
}

final class DeviceManagerImpl: DeviceManager, DeviceSetupManager {

    enum ConnectedDeviceState {
        case connected
        case updating
        case error
    }

    @WeakLazyInjected(\.spectrumDataRepository) private var spectrumDataRepository
    @WeakLazyInjected(\.spectrogramDataRepository) private var spectrogramDataRepository
    @WeakLazyInjected(\.dataBufferSetupRepository) private var dataBufferSetupRepository
