    @WeakLazyInjected(\.firmwareViewModel) private var firmwareViewModel
    @Injected(\.appInfo) private var appInfo
    @Injected(\.deviceContainer) private var deviceContainer

    enum DeviceManagerError: Error {
        case device
    }
    // MARK: Properties

    private var connectedDevice: BluetoothDevice?

    private var deviceCanncelables: AnyCancellable?

    @discardableResult
    func send<T: BluetoothCommand>(command: T) async -> Result<T.Response, Error> {
        guard let connectedDevice else {
            return .failure(DeviceManagerError.device)
        }
        return await connectedDevice.send(command: command)
    }

    let connectedDeviceSubject: PassthroughSubject<DeviceManagerImpl.ConnectedDeviceState, Never> = .init()

