Шаг 3 — изменения в [AlarmsLevelViewModel.swift](RadiaCode/Presentation/Containers/ControlCenter/DeviceInfo/Views/AlarmLevels/AlarmsLevelViewModel.swift). Применяю формулу из Protocol.pdf буквально (`uint32(val / DS_AlarmVsfrMul + 0.01)`), читая множитель из `deviceContainer.current?.configurationSettings.doseAlarmMultiplier`:

```swift
final class AlarmsLevelViewModel: ObservableObject {

    @Injected(\.deviceManager) private var deviceManager
    @Injected(\.deviceContainer) private var deviceContainer
    @Injected(\.dataBufferSetupRepository) private var dataBufferSetupRepository

    func updateAlarms(radiationType: RadiationType, level1: Decimal?, level2: Decimal?) async {
        let doseMultiplier = deviceContainer.current?.configurationSettings.doseAlarmMultiplier ?? 1
        if let level1 {
            await updateSettings(setting: radiationType.deviceSettingsLevel1, value: radiationType.deviceValue(value: level1, doseMultiplier: doseMultiplier))
        }
        if let level2 {
            await updateSettings(setting: radiationType.deviceSettingsLevel2, value: radiationType.deviceValue(value: level2, doseMultiplier: doseMultiplier))
        }
    }

    private func updateSettings(setting: BluetoothCommandOperation, value: UInt32) async {
        await deviceManager.send(command: SettingsCommand(
            setting: setting, action: .write, payload: value
        ))
    }
}

private extension RadiationType {

    var deviceSettingsLevel1: BluetoothCommandOperation { /* без изменений */ }
    var deviceSettingsLevel2: BluetoothCommandOperation { /* без изменений */ }

    func deviceValue(value: Decimal, doseMultiplier: UInt32) -> UInt32 {
        switch self {
        case .radiationLevel(let level):
            switch level {
            case .countRate:
                UInt32(value.floatValue * 10)
            case .doseRate:
                UInt32(value.floatValue * 100)
            }
        case .dose:
            // Protocol.pdf, гл. "Пороги по дозе": uint32(val / DS_AlarmVsfrMul + 0.01), float64
            UInt32(value.doubleValue / Double(doseMultiplier) + 0.01)
        }
    }
}
```

Изменения:
- Добавлен `@Injected(\.deviceContainer)` для доступа к подключённому устройству.
- `deviceValue` принимает `doseMultiplier`. Для `countRate`/`doseRate` логика без изменений.
- Для `.dose` — формула буквально из протокола, с `Double` (float64).
- При отсутствии устройства/множителя — fallback `1` (нейтральный, идентичен текущему поведению для старых прошивок).

Понял — давай сделаем рефакторинг чтобы encode/decode были в одном месте и симметричны. Сейчас логика разбросана: запись в `RadiationType.deviceValue`, чтение — инлайнами в `DeviceManager.getDeviceSettings`. Это плохо для проверки симметрии формул.

Предложение — добавить в [Alarm.swift](RadiaCode/Model/Alarm.swift) пару методов `encode`/`decode`, использовать их в обоих местах. Так заодно покрываем шаг 3 и 4:

```swift
extension Alarm.Level {

    /// Преобразование значения регистра устройства во внутреннее значение приложения.
    /// Формулы — Protocol.pdf, разделы "Пороги по скорости счёта" / "Пороги по дозе" / "Пороги по мощности дозы".
    static func decode(rawValue: UInt32, for type: RadiationType, doseAlarmMultiplier: UInt32) -> Decimal {
        switch type {
        case .radiationLevel(.countRate):
            Decimal(rawValue) / 10
        case .radiationLevel(.doseRate):
            Decimal(rawValue) / 100
        case .dose:
            // Protocol.pdf, "Пороги по дозе": val_μR = register × DS_AlarmVsfrMul
            Decimal(rawValue) * Decimal(doseAlarmMultiplier)
        }
    }

    /// Преобразование внутреннего значения приложения в значение регистра устройства.
    static func encode(value: Decimal, for type: RadiationType, doseAlarmMultiplier: UInt32) -> UInt32 {
        switch type {
        case .radiationLevel(.countRate):
            UInt32(value.floatValue * 10)
        case .radiationLevel(.doseRate):
            UInt32(value.floatValue * 100)
        case .dose:
            // Protocol.pdf, "Пороги по дозе": uint32(val / DS_AlarmVsfrMul + 0.01), float64
            UInt32(value.doubleValue / Double(doseAlarmMultiplier) + 0.01)
        }
    }
}
```

`AlarmsLevelViewModel` упрощается:

```swift
