}

private extension RadiationType {
    // только маппинг типа на BluetoothCommandOperation — без deviceValue
    var deviceSettingsLevel1: BluetoothCommandOperation { /* как сейчас */ }
    var deviceSettingsLevel2: BluetoothCommandOperation { /* как сейчас */ }
