```

И `DeviceManager.getDeviceSettings` — все 6 чтений порогов через единый помощник, использующий `Alarm.Level.decode`.

Прежде чем показывать `DeviceManager`-часть и применять — устраивает ли структура (encode/decode в `Alarm.Level`)?

Понял — централизовать всё в одно место и убрать разбросанные switch-case. Предложение — собрать всё в одном кодеке, который привязан к `Alarm.Level` (там уже есть `radiationType`):

```swift
extension Alarm.Level {

    /// Кодек преобразования значений порогов между приложением и регистрами устройства.
    /// Формулы — Protocol.pdf, главы "Пороги по скорости счёта" / "Пороги по дозе" / "Пороги по мощности дозы".
    struct DeviceCodec {
        let level1Operation: BluetoothCommandOperation
        let level2Operation: BluetoothCommandOperation
        let encode: (Decimal) -> UInt32
        let decode: (UInt32) -> Decimal
    }

    func deviceCodec(doseAlarmMultiplier: UInt32) -> DeviceCodec {
        switch radiationType {
        case .radiationLevel(.countRate):
            DeviceCodec(
                level1Operation: .countRateAlarmLevel1,
                level2Operation: .countRateAlarmLevel2,
                encode: { UInt32($0.floatValue * 10) },
                decode: { Decimal($0) / 10 }
            )
        case .radiationLevel(.doseRate):
            DeviceCodec(
                level1Operation: .doseRateAlarmLevel1,
                level2Operation: .doseRateAlarmLevel2,
                encode: { UInt32($0.floatValue * 100) },
                decode: { Decimal($0) / 100 }
            )
        case .dose:
            DeviceCodec(
                level1Operation: .doseAlarmLevel1,
                level2Operation: .doseAlarmLevel2,
                encode: { UInt32($0.doubleValue / Double(doseAlarmMultiplier) + 0.01) },
                decode: { Decimal($0) * Decimal(doseAlarmMultiplier) }
            )
        }
    }
}
```

Один switch-case с полной картиной по каждому типу — здесь сразу видна и операция, и формула.

`AlarmsLevelViewModel`:

