import Foundation
import FactoryKit

protocol DoseCounterSaveUseCase {

    func save(counterBatch: CounterBatch, backgroundDose: Double) async -> DoseCounter
}

final class DoseCounterSaveUseCaseImpl: DoseCounterSaveUseCase {

    @Injected(\.doseCounterRepository) private var doseCounterRepository

    private let deviceId: String

    init(deviceId: String) {
        self.deviceId = deviceId
    }

    func save(counterBatch: CounterBatch, backgroundDose: Double) async -> DoseCounter {
        let doseCounter = DoseCounter(
            id: UUID().uuidString,
            date: Date(timeIntervalSince1970: counterBatch.time),
            value: counterBatch.value,
            backgroundDose: backgroundDose
        )
        await doseCounterRepository.saveDoseCounter(deviceId: deviceId, doseCounter: doseCounter)
        return doseCounter
    }
}

