`AlarmsLevelViewModel` правда не похож на VM — он stateless, `ObservableObject` без `@Published`, `dataBufferSetupRepository` injected но не используется. Это типичный side-effect dispatcher → use case по конвенции проекта (см. `DoseCounterSaveUseCase`).

Предложение — заменить на `UpdateAlarmsUseCase`:

**Новый файл** `UpdateAlarmsUseCase.swift` (рядом, в той же папке):

```swift
import Foundation
import FactoryKit

extension Container {
    var updateAlarmsUseCase: Factory<UpdateAlarmsUseCase> {
        self { UpdateAlarmsUseCaseImpl() }
    }
}

protocol UpdateAlarmsUseCase {
    func update(alarmLevel: Alarm.Level, level1: Decimal?, level2: Decimal?) async
}

final class UpdateAlarmsUseCaseImpl: UpdateAlarmsUseCase {

    @Injected(\.deviceManager) private var deviceManager
    @Injected(\.deviceContainer) private var deviceContainer

    func update(alarmLevel: Alarm.Level, level1: Decimal?, level2: Decimal?) async {
        let codec = alarmLevel.deviceCodec(
            doseAlarmMultiplier: deviceContainer.current?.configurationSettings.doseAlarmMultiplier ?? 1
        )
        if let level1 {
            await write(setting: codec.level1Operation, value: codec.encode(level1))
        }
        if let level2 {
            await write(setting: codec.level2Operation, value: codec.encode(level2))
        }
    }

    private func write(setting: BluetoothCommandOperation, value: UInt32) async {
        await deviceManager.send(command: SettingsCommand(
            setting: setting, action: .write, payload: value
        ))
    }
}
```

**Удалить** `AlarmsLevelViewModel.swift` целиком (вместе с приватным расширением `RadiationType` — оно переехало в `Alarm.Level.deviceCodec`).

**`AlarmsLevelView`** — инжектим use case напрямую, без `@StateObject`:

```swift
struct AlarmsLevelView: View {

    @Injected(\.toast) private var toast
    @Injected(\.analyticsEngine) private var analyticsEngine
    @Injected(\.updateAlarmsUseCase) private var updateAlarmsUseCase

    @State private var selectedRadiationType: RadiationType?

    var alarms: Alarm

    var body: some View {
        VStack(alignment: .leading) {
            Text(.ControlCenter.alarmLevels)
                .font(.system(size: 13))
                .foregroundStyle(.textSecondary)
                .padding(.leading, 12)
            HStack(alignment: .top, spacing: 8) {
                ForEach([alarms.countRate, alarms.doseRate, alarms.dose].filter({ !$0.isEmpty }), id: \.radiationType) { alarmLevel in
                    Button {
                        analyticsEngine.reportEvent(AlarmsLevelAnalyticsEvent.alarmLevelSetupClick(alarmLevel.radiationType))
                        selectedRadiationType = alarmLevel.radiationType
                    } label: {
                        AlarmControlView(alarmLevel: alarmLevel)
                            .frame(maxWidth: .infinity, maxHeight: .infinity)
                    }
                    .buttonStyle(.plain)
                }
            }
        }
        .sheet(item: $selectedRadiationType) { radiationType in
            let binding = binding(for: radiationType)
            AlarmLevelSetupView(alarmLevel: binding) { level1, level2 in
                Task {
                    await updateAlarmsUseCase.update(alarmLevel: binding.wrappedValue, level1: level1, level2: level2)
                    toast.show(style: .success, message: .ControlCenter.deviceSettingsUpdated)
                }
            }
            .interactiveDismissDisabled()
        }
    }

    private func binding(for type: RadiationType) -> Binding<Alarm.Level> {
        @Bindable var alarms = alarms
        switch type {
        case .radiationLevel(.countRate): return $alarms.countRate
        case .radiationLevel(.doseRate): return $alarms.doseRate
        case .dose: return $alarms.dose
        }
    }
}
```

Что улучшится:
- Класс больше не `ObservableObject` без причин.
- Неиспользуемый `dataBufferSetupRepository` уходит.
- Только один switch-case (в `deviceCodec`), там же видна формула из протокола.
- Use case вписывается в конвенцию проекта.

