@MainActor
private func getDeviceSettings(connectedDevice: BluetoothDevice) async {
    let controlResult = await connectedDevice.send(command: SettingsCommand(setting: .deviceControl))
    if case .success(let response) = controlResult {
        await self.settingComposer.set(raw: response.register, value: response.value)
    }

    let soundResult = await connectedDevice.send(command: SettingsCommand(setting: .soundControl))
    if case .success(let response) = soundResult {
        await self.settingComposer.set(raw: response.register, value: response.value)
    }

    let vibroResult = await connectedDevice.send(command: SettingsCommand(setting: .vibroControl))
    if case .success(let response) = vibroResult {
        await self.settingComposer.set(raw: response.register, value: response.value)
    }

    let temperatureUnit = await connectedDevice.send(command: SettingsCommand(setting: .temperatureUnit))
    if case .success(let response) = temperatureUnit {
        connectedDevice.settings.temperatureUnit = TemperatureUnit(rawValue: response.value) ?? .celsius
    }

    await readAlarmLevels(on: connectedDevice, into: \.countRate, type: .radiationLevel(.countRate), level1: .countRateAlarmLevel1, level2: .countRateAlarmLevel2)
    await readAlarmLevels(on: connectedDevice, into: \.doseRate, type: .radiationLevel(.doseRate), level1: .doseRateAlarmLevel1, level2: .doseRateAlarmLevel2)
    await readAlarmLevels(on: connectedDevice, into: \.dose, type: .dose, level1: .doseAlarmLevel1, level2: .doseAlarmLevel2)
}

private func readAlarmLevels(
    on device: BluetoothDevice,
    into keyPath: WritableKeyPath<Alarm, Alarm.Level>,
    type: RadiationType,
    level1: BluetoothCommandOperation,
    level2: BluetoothCommandOperation
) async {
    let multiplier = device.configurationSettings.doseAlarmMultiplier
    if let value = await readAlarmRegister(on: device, setting: level1, type: type, doseAlarmMultiplier: multiplier) {
        device.alarms[keyPath: keyPath].level1 = value
    }
    if let value = await readAlarmRegister(on: device, setting: level2, type: type, doseAlarmMultiplier: multiplier) {
        device.alarms[keyPath: keyPath].level2 = value
    }
}

private func readAlarmRegister(
    on device: BluetoothDevice,
    setting: BluetoothCommandOperation,
    type: RadiationType,
    doseAlarmMultiplier: UInt32
) async -> Decimal? {
    let result = await device.send(command: SettingsCommand(setting: setting))
    guard case .success(let response) = result else { return nil }
    return Alarm.Level.decode(rawValue: response.value, for: type, doseAlarmMultiplier: doseAlarmMultiplier)
}
