private func readAlarmLevels(_ level: Alarm.Level, on device: BluetoothDevice) async -> Alarm.Level {
    let type = level.radiationType
    let multiplier = device.configurationSettings.doseAlarmMultiplier
    var updated = level
    if case .success(let response) = await device.send(command: SettingsCommand(setting: type.deviceSettingsLevel1)) {
        updated.level1 = Alarm.Level.decode(rawValue: r.value, for: type, doseAlarmMultiplier: multiplier)
    }
    if case .success(let r) = await device.send(command: SettingsCommand(setting: type.deviceSettingsLevel2)) {
        updated.level2 = Alarm.Level.decode(rawValue: r.value, for: type, doseAlarmMultiplier: multiplier)
    }
    return updated
}

@MainActor
private func getFirmwareInfo(connectedDevice: BluetoothDevice) async {
    let versionResult = await connectedDevice.send(command: FirmwareCommand.GetVersion())
    if case .success(let response) = versionResult {
        analyticsEngine?.setupUser(deviceId: appInfo.uniqueDeviceId, radiaCodeDevice: connectedDevice.identifier, firmware: response.target.version)
        connectedDevice.firmware.version = response
    }

    let signatureResult = await connectedDevice.send(command: FirmwareCommand.ReadFlashSiganture())
    if case .success(let response) = signatureResult {
        connectedDevice.firmware.signature = response
    }        
}

@MainActor
private func fetchEnergyCalibration(for device: BluetoothDevice) async {
    guard !device.spectrumDisabled else { return }
    let result = await device.send(command: EnergyCalibrationCommand(action: .read))
    guard case .success(let response) = result else { return }
    let coefficients = response.coefficients

    guard coefficients.count >= 3 else {
        Log.error("Coefficients error: \(response)")
        return
    }

    device.spectrumSettings.coefficients = .init(
        a0: coefficients[0],
        a1: coefficients[1],
        a2: coefficients[2]
    )
}

func startRealTimeData() {
    dataBufferSetupRepository?.startBufferCollect()
    spectrumDataRepository?.startSpectrumCollect()
}

