init(alarmLevel: Alarm.Level) {
    self.alarmLevel = alarmLevel
    let radiationType = alarmLevel.radiationType

    func makeValues(minStep: Decimal, switchAt: Decimal) -> [Decimal] {
        let maxValue = alarmLevel.offScale ?? radiationType.defaultMaxValue

        func step(for value: Decimal) -> Decimal {
            var step = minStep
            var threshold = switchAt

            while value >= threshold * 10 {
                step *= 10
                threshold *= 10
            }

            return step
        }

        var values: [Decimal] = []
        var value = maxValue

        while value >= 0 {
            values.append(value)
            if value == 0 { break }

            value -= step(for: value)
            if value < 0 {
                value = 0
            }
        }

        return values
    }

    let values: [Decimal] = {
        switch radiationType {
        case .radiationLevel(let level):
            switch level {
            case .countRate:
                makeValues(minStep: 0.1, switchAt: 20)

            case .doseRate:
                makeValues(minStep: 0.01, switchAt: 2)
            }

        case .dose:
            makeValues(minStep: 1, switchAt: 100)
        }
    }()

    self.displayedValueLevel1 = .init(initialValue: alarmLevel.level1 ?? 0, radiationType: radiationType, values: values)
    self.displayedValueLevel2 = .init(initialValue: alarmLevel.level2 ?? 0, radiationType: radiationType, values: values)

    let state = LastState(last1: displayedValueLevel1.selectedValue, last2: displayedValueLevel2.selectedValue)

    withObservationTracking { [weak self] in
        guard let self else { return }
        let level1 = self.displayedValueLevel1.selectedValue
        let level2 = self.displayedValueLevel2.selectedValue

        let level1Changed = (level1 != state.last1)
        let level2Changed = (level2 != state.last2)

        defer {
            state.last1 = level1
            state.last2 = level2
        }

        if level2Changed && !level1Changed {
            // двигают level2 -> level1 следует за ним
            if level2 < level1 {
                self.displayedValueLevel1.selectedValue = level2
            }
        } else if level1Changed && !level2Changed {
            // двигают level1 -> level2 следует за ним
            if level1 > level2 {
                self.displayedValueLevel2.selectedValue = level1
            }
        }

content.text:
Понял баг. При `offScale = 9999.99` цикл вычитания шага начинается с `9999.99` → даёт `9989.99 → ... → 9.99 → 8.99 → ... → 0.99 → 0`. Дробная часть `.99` тянется через все значения, поэтому вместо целочисленных шагов «1, 2, 3, …» получается «0.99, 1.99, 2.99, …». В UI после форматирования смотрится как «0.9, 2, 3, …».

Исправление: после первого добавления `maxValue` (offScale) спускаться к ближайшему целочисленному кратному текущего шага.

Например:

```swift
var values: [Decimal] = []
var value = maxValue
values.append(value)

// Снап к нижнему кратному текущего шага, чтобы остальные значения были на ровных границах
let firstStep = step(for: value)
var snapped = Decimal()
var divided = value / firstStep
NSDecimalRound(&snapped, &divided, 0, .down)
value = snapped * firstStep
if value == maxValue {
    value -= firstStep
}

while value >= 0 {
    values.append(value)
    if value == 0 { break }
    value -= step(for: value)
    if value < 0 { value = 0 }
}
```

Для `offScale=9999.99` это даст: `9999.99, 9990, 9980, …, 10, 9, 8, …, 1, 0` — то что ты ожидаешь.

Этот фикс по сути не относится к RAD-1172 (это UI-баг в барабане, вылез из-за того что Zero возвращает offScale=9999.99 с дробной частью). Можно:

Окей, вариант C — округление `maxValue` вверх до ближайшего кратного текущего шага (`9999.99 → 10000`).

Изменение в [AlarmLevelSetupViewModel.swift](RadiaCode/Presentation/Containers/ControlCenter/DeviceInfo/Views/AlarmLevels/AlarmLevelSetupViewModel.swift), функция `makeValues`:

```swift
func makeValues(minStep: Decimal, switchAt: Decimal) -> [Decimal] {
    let rawMax = alarmLevel.offScale ?? radiationType.defaultMaxValue

    func step(for value: Decimal) -> Decimal {
        var step = minStep
        var threshold = switchAt

        while value >= threshold * 10 {
            step *= 10
            threshold *= 10
        }

        return step
    }

    // Округляем maxValue вверх до ближайшего кратного шага, чтобы все значения барабана были целочисленные.
    let topStep = step(for: rawMax)
    var ceiled = Decimal()
    var divided = rawMax / topStep
    NSDecimalRound(&ceiled, &divided, 0, .up)
    let maxValue = ceiled * topStep

    var values: [Decimal] = []
    var value = maxValue

    while value >= 0 {
        values.append(value)
        if value == 0 { break }

        value -= step(for: value)
        if value < 0 {
            value = 0
        }
    }

    return values
}
```

Для `offScale = 9999.99` (dose, `switchAt: 100`):
- `topStep = step(9999.99) = 10` (т.к. `9999.99 >= 1000`)
- `9999.99 / 10 = 999.999`, ceil → `1000`, × 10 → `maxValue = 10000`
- Барабан: `10000, 9990, …, 10, 9, 8, …, 1, 0` — всё на круглых числах.

Этот фикс — отдельный, к `RAD-1172` напрямую не относится (вылез как побочка). Можно либо включить в этот PR, либо вынести отдельным тикетом — на твоё усмотрение.
